// ============================================================
// Holigenix Outreach Agent — Configuration
// ============================================================
// SETUP: Replace YOUR_* placeholders with real credentials
// Then set DRY_RUN to false when ready to send live emails
// ============================================================

return [{
  json: {
    // Supabase (Holigenix Growth Engine)
    SUPABASE_URL: 'https://shrxkkbgmckbezmlssbg.supabase.co',
    SUPABASE_SERVICE_KEY: 'YOUR_HOLIGENIX_SUPABASE_SERVICE_KEY',

    // Claude API (for email drafting)
    ANTHROPIC_API_KEY: 'YOUR_ANTHROPIC_API_KEY',

    // Gmail (send from admin@holigenixhealthcare.com)
    // Use OAuth access token from Google Cloud Console
    GMAIL_ACCESS_TOKEN: 'YOUR_GMAIL_OAUTH_ACCESS_TOKEN',
    SENDER_EMAIL: 'admin@holigenixhealthcare.com',
    SENDER_NAME: 'Rodney Williams',

    // Campaign settings
    MAX_EMAILS_PER_RUN: 5,
    DRY_RUN: true  // true = draft + log only, false = draft + send + log
  }
}];

// ============================================================
// Query Supabase for contacts due for outreach
// Applies cadence rules from outreach_agent_prompt.md:
//   New → introductory (immediate)
//   Contacted (no reply) → follow_up (every 10-14d, max 3)
//   Engaged → nurture (every 7-10d)
//   Active Partner → thank_you (every 14-21d)
//   Cold → re_engagement (at 30d, then monthly)
//   Exhausted (3+ no reply) → SKIP
// ============================================================
const cfg = $('Config').first().json;
const headers = {
  'apikey': cfg.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + cfg.SUPABASE_SERVICE_KEY
};
const today = new Date().toISOString().split('T')[0];

// 1. Fetch all contacts with email addresses
let contacts = [];
try {
  contacts = await this.helpers.httpRequest({
    method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/crm_referral_sources?select=*&email=not.is.null&order=relationship_score.desc',
    headers
  });
} catch(e) {
  return [{ json: { error: 'Failed to fetch contacts: ' + e.message, contacts_due: 0, batch: [] }}];
}

// 2. Fetch recent outreach emails (last 60 days)
let recentEmails = [];
try {
  const cutoff = new Date(Date.now() - 60 * 24 * 60 * 60 * 1000).toISOString();
  recentEmails = await this.helpers.httpRequest({
    method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/outreach_emails?select=contact_email,sent_at,campaign_type,status&sent_at=gte.' + cutoff + '&order=sent_at.desc',
    headers
  });
} catch(e) { /* table may not exist yet — OK for first run */ }

// 3. Build outreach history lookup
const historyMap = {};
for (const em of recentEmails) {
  if (!historyMap[em.contact_email]) historyMap[em.contact_email] = [];
  historyMap[em.contact_email].push(em);
}

// 4. Fetch hospital directory for enrichment
let hospitals = [];
try {
  hospitals = await this.helpers.httpRequest({
    method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/hospital_directory?select=name,nicu_flag,pediatric_flag,tier,city',
    headers
  });
} catch(e) {}
const hospMap = {};
for (const h of hospitals) { hospMap[h.name] = h; }

// 5. Apply cadence rules
const due = [];
for (const c of contacts) {
  const history = historyMap[c.email] || [];
  const stage = (c.stage || 'new').toLowerCase();
  const outreachCount = history.length;
  const lastSent = history.length > 0 ? new Date(history[0].sent_at) : null;
  const daysSince = lastSent
    ? Math.floor((Date.now() - lastSent.getTime()) / 86400000)
    : 999;

  let messageType = null;
  let priority = 0;

  if (stage === 'exhausted' || (stage === 'contacted' && outreachCount >= 3)) {
    continue; // SKIP exhausted contacts
  } else if ((stage === 'new' || !stage) && outreachCount === 0) {
    messageType = 'introductory';
    priority = 80;
  } else if (stage === 'contacted' && daysSince >= 10) {
    messageType = 'follow_up';
    priority = 90; // overdue follow-ups are highest priority
  } else if (stage === 'engaged' && daysSince >= 7) {
    messageType = 'nurture';
    priority = 70;
  } else if (stage === 'active_partner' && daysSince >= 14) {
    messageType = 'thank_you';
    priority = 50;
  } else if (stage === 'cold' && daysSince >= 30) {
    messageType = 're_engagement';
    priority = 60;
  }

  if (messageType) {
    const hosp = hospMap[c.organization || c.company_name] || {};
    due.push({
      contact_name: c.contact_name || c.name || ((c.first_name || '') + ' ' + (c.last_name || '')).trim(),
      email: c.email,
      title: c.title || '',
      organization: c.organization || c.company_name || '',
      department: c.department || '',
      stage: c.stage,
      relationship_score: c.relationship_score || 0,
      hospital_nicu_flag: hosp.nicu_flag || c.hospital_nicu_flag || false,
      hospital_tier: hosp.tier || c.hospital_tier || null,
      message_type: messageType,
      priority,
      outreach_count: outreachCount,
      days_since_last_email: daysSince
    });
  }
}

// Sort by priority desc, cap at MAX_EMAILS_PER_RUN
due.sort((a, b) => b.priority - a.priority);
const batch = due.slice(0, cfg.MAX_EMAILS_PER_RUN);

return [{ json: {
  contacts_due: batch.length,
  contacts_total: contacts.length,
  contacts_skipped: contacts.length - batch.length,
  batch,
  date: today
}}];

// ============================================================
// Outreach Agent — Draft personalized emails via Claude
// System prompt encodes all rules from outreach_agent_prompt.md
// ============================================================
const cfg = $('Config').first().json;
const data = $input.first().json;
const batch = data.batch;

if (!batch || batch.length === 0) {
  return [{ json: { drafts: [], count: 0, errors: 0 }}];
}

const SYSTEM_PROMPT = `You are the Outreach Agent for Holigenix Healthcare LLC — a GAPP-approved pediatric home healthcare agency in Georgia specializing in technology-dependent children (ventilators, tracheostomies, gastrostomy tubes).

You draft personalized outreach emails to hospital referral sources (NICU social workers, discharge planners, pediatric case managers).

RULES:
- Clinical credibility first — frame Holigenix as a resource, never a sales pitch
- Professional but warm — these are healthcare professionals, not buyers
- Under 200 words per email
- No emojis, no exclamation marks, no ALL CAPS
- No generic "just checking in" — every email must provide value or a specific ask
- Sign off as: Rodney Williams, Holigenix Healthcare LLC, admin@holigenixhealthcare.com
- NEVER reference PHI, patient names, discharge lists, or private hospital systems
- NEVER make promises about staffing capacity without verification
- NEVER fabricate contact details, hospital data, or referral numbers
- ALWAYS include a clear, single call-to-action
- ALWAYS reference the contact's specific role and hospital when possible
- Lead with what Holigenix can do for THEIR families/team

ABOUT HOLIGENIX:
- Medicaid-approved pediatric home healthcare in Georgia
- GAPP (Georgia Pediatric Program) approved
- Specializes in technology-dependent children: vents, trachs, g-tubes, central lines
- Known for fast intake and reliable staffing for the most complex cases
- Accepts ALL Georgia Medicaid MCOs: Peach State, CareSource, Amerigroup, WellCare, Meridian
- Service area: Metro Atlanta, Northeast GA, Middle GA, Augusta, expanding South GA

MESSAGE TYPES:
- introductory: First contact. Introduce Holigenix, ask for a brief call or in-service.
- follow_up: 2nd/3rd attempt. Reference previous outreach, add a value prop, low pressure.
- nurture: Contact has engaged. Share a relevant update, maintain relationship.
- thank_you: Active referral partner. Express appreciation, share a win or update.
- re_engagement: Was active, went quiet. Share something new, reopen the door.

Respond with ONLY valid JSON (no markdown, no code blocks, no explanation).`;

const drafts = [];

for (const contact of batch) {
  const userMsg = `Draft an email for this contact.

CONTACT:
- Name: ${contact.contact_name}
- Title: ${contact.title || 'Healthcare Professional'}
- Organization: ${contact.organization || 'Hospital'}
- Department: ${contact.department || 'Not specified'}
- Current Stage: ${contact.stage}
- Relationship Score: ${contact.relationship_score}/100
- Previous Emails Sent: ${contact.outreach_count}
- Days Since Last Email: ${contact.days_since_last_email}
- Hospital Has NICU: ${contact.hospital_nicu_flag ? 'Yes' : 'Unknown'}
- Hospital Tier: ${contact.hospital_tier || 'Unknown'}

MESSAGE TYPE: ${contact.message_type}

Return JSON:
{"subject": "...", "body": "...", "message_type": "${contact.message_type}", "cta": "the specific call to action"}`;

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': cfg.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      },
      body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1024,
        system: SYSTEM_PROMPT,
        messages: [{ role: 'user', content: userMsg }]
      },
      timeout: 30000
    });

    let text = resp.content.map(c => c.text || '').join('').trim();
    // Strip markdown code fences if Claude wraps the JSON
    text = text.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
    const draft = JSON.parse(text);

    drafts.push({
      contact_name: contact.contact_name,
      contact_email: contact.email,
      company_name: contact.organization,
      department: contact.department,
      subject: draft.subject,
      body: draft.body,
      message_type: draft.message_type || contact.message_type,
      cta: draft.cta,
      stage: contact.stage,
      hospital_tier: contact.hospital_tier,
      relationship_score: contact.relationship_score,
      outreach_count: contact.outreach_count
    });
  } catch(e) {
    drafts.push({
      contact_name: contact.contact_name,
      contact_email: contact.email,
      company_name: contact.organization,
      error: 'Draft failed: ' + e.message,
      message_type: contact.message_type
    });
  }

  // Rate limit between Claude API calls
  await new Promise(r => setTimeout(r, 500));
}

return [{ json: {
  drafts,
  count: drafts.filter(d => !d.error).length,
  errors: drafts.filter(d => d.error).length
}}];

// ============================================================
// Send emails via Gmail API + log to Supabase outreach_emails
// Respects DRY_RUN: true = draft+log only, false = send+log
// ============================================================
const cfg = $('Config').first().json;
const data = $input.first().json;
const drafts = data.drafts.filter(d => !d.error);
const sbHeaders = {
  'apikey': cfg.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + cfg.SUPABASE_SERVICE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

let sent = 0;
let logged = 0;
let failed = 0;
const results = [];

for (const draft of drafts) {
  let emailStatus = cfg.DRY_RUN ? 'draft' : 'pending';

  // === SEND via Gmail API (only when DRY_RUN is false) ===
  if (!cfg.DRY_RUN && cfg.GMAIL_ACCESS_TOKEN && cfg.GMAIL_ACCESS_TOKEN !== 'YOUR_GMAIL_OAUTH_ACCESS_TOKEN') {
    try {
      // Build RFC 2822 email message
      const emailLines = [
        'From: ' + cfg.SENDER_NAME + ' <' + cfg.SENDER_EMAIL + '>',
        'To: ' + draft.contact_email,
        'Subject: ' + draft.subject,
        'Content-Type: text/plain; charset=utf-8',
        '',
        draft.body
      ];
      const rawEmail = Buffer.from(emailLines.join('\r\n'))
        .toString('base64')
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=+$/, '');

      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://gmail.googleapis.com/gmail/v1/users/me/messages/send',
        headers: {
          'Authorization': 'Bearer ' + cfg.GMAIL_ACCESS_TOKEN,
          'Content-Type': 'application/json'
        },
        body: { raw: rawEmail },
        timeout: 15000
      });

      emailStatus = 'sent';
      sent++;
    } catch(e) {
      emailStatus = 'send_failed';
      failed++;
      results.push({ contact: draft.contact_name, send_error: e.message });
    }
  } else if (cfg.DRY_RUN) {
    sent++; // Count drafts as successful in dry-run mode
  } else {
    emailStatus = 'send_failed';
    failed++;
    results.push({ contact: draft.contact_name, send_error: 'Gmail token not configured' });
  }

  // === LOG to Supabase outreach_emails table ===
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: cfg.SUPABASE_URL + '/rest/v1/outreach_emails',
      headers: sbHeaders,
      body: {
        contact_name: draft.contact_name,
        contact_email: draft.contact_email,
        company_name: draft.company_name,
        subject: draft.subject,
        body: draft.body,
        status: emailStatus,
        campaign_type: draft.message_type,
        sent_at: emailStatus === 'sent' ? new Date().toISOString() : null,
        metadata: {
          message_type: draft.message_type,
          cta: draft.cta,
          hospital_tier: draft.hospital_tier,
          relationship_score: draft.relationship_score,
          generated_by: 'outreach_agent',
          dry_run: cfg.DRY_RUN
        }
      }
    });
    logged++;
  } catch(e) {
    results.push({ contact: draft.contact_name, log_error: e.message });
  }

  // === UPDATE contact stage (only if actually sent) ===
  if (emailStatus === 'sent' && !cfg.DRY_RUN) {
    try {
      const updates = { last_contacted_at: new Date().toISOString() };
      // Move 'new' contacts to 'contacted' after first email
      if (draft.stage === 'new') updates.stage = 'contacted';

      await this.helpers.httpRequest({
        method: 'PATCH',
        url: cfg.SUPABASE_URL + '/rest/v1/crm_referral_sources?email=eq.' + encodeURIComponent(draft.contact_email),
        headers: sbHeaders,
        body: updates
      });
    } catch(e) {}
  }

  // Rate limit between sends
  await new Promise(r => setTimeout(r, 200));
}

return [{ json: {
  campaign: 'holigenix_outreach',
  date: new Date().toISOString().split('T')[0],
  dry_run: cfg.DRY_RUN,
  drafts_total: drafts.length,
  sent,
  logged,
  failed,
  errors: results
}}];
